  if (parts.length !== 3 || parts[0] !== "" || parts[1] !== "apps") {
    return null;
  }

  const slug = parts[2];

  if (!isGitHubAppSlug(slug)) {
    return null;
  }

  return {
    audience: value,
    slug,
  };
}

export function isGitHubAppSlug(value: string | undefined): value is string {
  return value !== undefined && /^[a-z0-9](?:[a-z0-9-]*[a-z0-9])?$/u.test(value);
}

